import React from "react";
import "../WelcomeMessage.css";

class WelcomeMessage extends React.Component {
  render() {
    return (
      <div className="welcome-chat-wrapper">
        <div className="welcome-chat-card">
          <div className="welcome-chat-title">
            👋 Benvenuto!
          </div>

          <div className="welcome-chat-body">
            Questa è la mia pagina personale, uno spazio dedicato ai miei
            progetti, alle mie competenze e alle risorse che sviluppo e
            condivido nel tempo. Qui troverai codice, idee e sperimentazioni
            legate al mondo dello sviluppo software e dei sistemi.
          </div>

          <div className="welcome-chat-footer">
            👉 Esplora il menu di navigazione per scoprire repository, risorse
            tecniche e contenuti disponibili su questa pagina.
          </div>
        </div>
      </div>
    );
  }
}

export default WelcomeMessage;
